 	ssdtosd(&gdt_segs[GUSERLDT_SEL], &gdt[GUSERLDT_SEL].sd);
 	lldt(GSEL(GUSERLDT_SEL, SEL_KPL));
 	currentldt = GSEL(GUSERLDT_SEL, SEL_KPL);
@@ -301,6 +309,13 @@

 	if (pcb->pcb_ldt) {
 		nldt = pcb->pcb_ldt_len;
