                 union descriptor *new_ldt;
-                size_t len = pcb2->pcb_ldt_len * sizeof(union descriptor);
+                int nldt = pcb2->pcb_ldt_len;

-                new_ldt = (union descriptor *)kmem_alloc(kernel_map, len);
